import sqlite3
from pathlib import Path

# Database connection
conn = sqlite3.connect('permissions.db')
cursor = conn.cursor()

def get_file_contents(user, file_path):
    """
    Checks user permission and returns file contents.

    Args:
        user: Username.
        file_path: Path to the file.

    Returns:
        File contents if permission granted, None otherwise.
    """

    # Check user permission in the database
    cursor.execute("SELECT permission FROM users WHERE username = ?", (user,))
    permission = cursor.fetchone()[0]

    if permission == 'read':
        # Open and return file contents
        with open(Path(file_path), 'r') as f:
            return f.read()
    else:
        return None

# Close database connection
